import android.util.Log
val TAG = "KotlinInAppPaymentModule"
interface Payable {
    fun pay()

    companion object {
        private val MIN_AMOUNT = 10
        private var totalAmount = -MIN_AMOUNT

        internal fun getPaid(amount: Int): Int? {
            return if (amount > totalAmount || amount <= 5) null else {
                Log.i(TAG, "Payable with Rs. $amount")

                totalAmount -= amount
                amount
            }
        }
    }
}

